import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useArticle } from '../context/ArticleContext';
import { API_BASE_URL } from '../config';

const ArticleDetail = () => {
  const { id } = useParams();
  const { user } = useAuth();
  const { updateArticleStats } = useArticle();
  const navigate = useNavigate();
  const [article, setArticle] = useState(null);
  const [showPaywall, setShowPaywall] = useState(false);

  useEffect(() => {
    fetchArticle();
    incrementViewCount();
  }, [id]);

  const fetchArticle = async () => {
    const token = localStorage.getItem('token');
    const res = await fetch(`${API_BASE_URL}/articles/${id}`, {
      headers: token ? { 'Authorization': `Bearer ${token}` } : {}
    });
    const data = await res.json();
    setArticle(data);

    if (data.isPaid && (!user || !user.isPremium)) {
      setShowPaywall(true);
    }
  };

  const incrementViewCount = async () => {
    try {
      const res = await fetch(`${API_BASE_URL}/articles/${id}/view`, {
        method: 'POST'
      });
      const data = await res.json();
      // 更新文章的浏览次数
      setArticle(prev => prev ? { ...prev, views: data.views } : null);
      // 同步到全局状态
      updateArticleStats(id, { views: data.views });
    } catch (error) {
      console.error('Failed to increment view count:', error);
    }
  };

  const handleLike = async () => {
    const token = localStorage.getItem('token');
    const res = await fetch(`${API_BASE_URL}/articles/${id}/like`, {
      method: 'POST',
      headers: { 'Authorization': `Bearer ${token}` }
    });
    const data = await res.json();
    // 更新本地状态
    setArticle(prev => prev ? { ...prev, likes: data.likes } : null);
    // 同步到全局状态
    updateArticleStats(id, { likes: data.likes });
  };

  if (!article) return <div style={styles.loading}>加载中...</div>;

  const displayContent = showPaywall 
    ? article.content.substring(0, Math.floor(article.content.length / 8))
    : article.content;

  return (
    <div style={styles.container}>
      <article style={styles.article}>
        <img src={article.coverImage} alt={article.title} style={styles.coverImage} />
        <h1 style={styles.title}>{article.title}</h1>
        <div style={styles.meta}>
          <span>作者：{article.author}</span>
          <span>{new Date(article.createdAt).toLocaleDateString('zh-CN')}</span>
        </div>
        <div style={styles.tags}>
          {article.tags?.map(tag => (
            <span key={tag} style={styles.tag}>{tag}</span>
          ))}
        </div>
        <div style={styles.content}>
          {displayContent}
        </div>

        {showPaywall && (
          <div style={styles.paywall}>
            <div style={styles.paywallOverlay}></div>
            <div style={styles.paywallContent}>
              <h3>解锁全文</h3>
              <p>开通会员即可阅读完整内容</p>
              <button onClick={() => navigate('/membership')} style={styles.paywallBtn}>
                开通会员 ¥39.99/月
              </button>
            </div>
          </div>
        )}

        <div style={styles.actions}>
          <button onClick={handleLike} style={styles.likeBtn}>
            ❤️ 点赞 {article.likes || 0}
          </button>
          <div style={styles.viewCount}>
            👁️ 浏览 {article.views || 0}
          </div>
        </div>
      </article>
    </div>
  );
};

const styles = {
  container: {
    maxWidth: '800px',
    margin: '2rem auto',
    padding: '0 1rem',
  },
  loading: {
    textAlign: 'center',
    padding: '4rem',
  },
  article: {
    background: '#fff',
    borderRadius: '12px',
    padding: '2rem',
    boxShadow: '0 2px 8px rgba(0,0,0,0.1)',
    position: 'relative',
  },
  coverImage: {
    width: '100%',
    height: '400px',
    objectFit: 'cover',
    borderRadius: '8px',
    marginBottom: '2rem',
  },
  title: {
    fontSize: '2rem',
    marginBottom: '1rem',
    color: '#111827',
  },
  meta: {
    display: 'flex',
    gap: '2rem',
    color: '#6b7280',
    marginBottom: '1rem',
  },
  tags: {
    display: 'flex',
    gap: '0.5rem',
    marginBottom: '2rem',
  },
  tag: {
    background: '#e0e7ff',
    color: '#4f46e5',
    padding: '0.25rem 0.75rem',
    borderRadius: '12px',
    fontSize: '0.875rem',
  },
  content: {
    lineHeight: '1.8',
    fontSize: '1.1rem',
    color: '#374151',
    whiteSpace: 'pre-wrap',
  },
  paywall: {
    position: 'relative',
    marginTop: '-100px',
  },
  paywallOverlay: {
    height: '200px',
    background: 'linear-gradient(to bottom, transparent, white)',
  },
  paywallContent: {
    textAlign: 'center',
    padding: '2rem',
    background: '#f9fafb',
    borderRadius: '12px',
    marginTop: '1rem',
  },
  paywallBtn: {
    marginTop: '1rem',
    padding: '1rem 2rem',
    background: '#fbbf24',
    color: '#000',
    borderRadius: '24px',
    fontSize: '1rem',
    fontWeight: 'bold',
  },
  actions: {
    marginTop: '2rem',
    display: 'flex',
    gap: '1rem',
  },
  likeBtn: {
    padding: '0.75rem 1.5rem',
    background: '#fee2e2',
    color: '#dc2626',
    borderRadius: '24px',
    fontSize: '1rem',
  },
  viewCount: {
    padding: '0.75rem 1.5rem',
    background: '#f3f4f6',
    color: '#6b7280',
    borderRadius: '24px',
    fontSize: '1rem',
    display: 'flex',
    alignItems: 'center',
    gap: '0.5rem',
  },
};

export default ArticleDetail;
